const REPORT_CHAT_ID = $env.REPORT_CHAT_ID || 'TELEGRAM_CHAT_ID_HERE';

const input = $json;
const now = new Date().toISOString();

const isTelegram = Boolean(input.message && input.message.chat);

const commandMap = {
  '/report': 'full',
  '/health': 'health',
  '/speed': 'speed',
  '/help': 'help'
};

if (isTelegram) {
  const text = (input.message.text || '').trim();
  const chatId = String(input.message.chat.id);
  const messageId = input.message.message_id;
  const commandRaw = text.split(/\s+/)[0] || '';
  const command = commandRaw.replace(/@\w+$/, '').toLowerCase();
  const runMode = commandMap[command] || null;

  return [
    {
      json: {
        source: 'telegram',
        should_run: Boolean(runMode),
        chat_id: chatId,
        message_id: messageId,
        command,
        run_mode: runMode || 'unknown',
        requested_at: now,
        is_manual: true
      }
    }
  ];
}

return [
  {
    json: {
      source: 'schedule',
      should_run: true,
      chat_id: REPORT_CHAT_ID,
      message_id: null,
      command: 'schedule',
      run_mode: 'full',
      requested_at: now,
      is_manual: false
    }
  }
];

const runMode = $json.run_mode;

const runHealth = runMode === 'full' || runMode === 'health';
const runSpeed = runMode === 'full' || runMode === 'speed';

const CONFIG = {
  project_slug: '',
  project_name: '',
  base_url: '',

  product_path: '',
  cart_path: '',

  health_runner_url: '',
  health_runner_api_key: $env.HEALTH_RUNNER_API_KEY || '',

  speed_json_url: '',
  speed_image_url: '',
  speed_runner_api_key: $env.SPEED_RUNNER_API_KEY || '',

  health_timeout_ms: 45000,
  speed_timeout_ms: 60000,

  health_checks: [
    'home_page_open',
    'product_page_open',
    'cart_page_open'
  ],

  health_block_resource_types: [
    'image',
    'media',
    'font'
  ],

  health_include_screenshots: false,
  health_artifact_limit: 20,
  health_locale: 'en-US',

  speed_reference_pages: [],

  selectors: {
    product_gallery: '',
    add_to_cart_button: '',
    cart_count: '',
    cart_total: '',
    cart_item: '',
    cart_remove_button: '',
    accessory_option: '',
    accessory_update_button: '',
    motivator_open_button: '',
    motivator_card: ''
  },

  product: {
    expected_title_contains: '',
    expected_quantity_after_update: 1,
    accessory_variants: []
  },

  expectations: {
    base_accessory_id: '',
    expected_paid_accessory_example: '',
    expected_add_delta: 1,
    expected_accessory_add_delta: 1,
    expected_update_delta: 0,
    expected_double_click_delta: 1,
    expected_quantity_after_update: 1,
    motivator_max_discount_total: 30000
  }
};

function joinUrl(base, path) {
  if (!base) return '';
  if (!path) return base.replace(/\/+$/, '');
  return `${base.replace(/\/+$/, '')}/${path.replace(/^\/+/, '')}`;
}

const now = new Date();
const reportId = `${CONFIG.project_slug || 'project'}_${now.toISOString().replace(/[:.]/g, '-')}`;

const homeUrl = CONFIG.base_url ? `${CONFIG.base_url.replace(/\/+$/, '')}/` : '';
const productUrl = joinUrl(CONFIG.base_url, CONFIG.product_path);
const cartUrl = joinUrl(CONFIG.base_url, CONFIG.cart_path);

return [
  {
    json: {
      report_id: reportId,
      source: $json.source,
      command: $json.command,
      run_mode: runMode,
      is_manual: $json.is_manual,
      requested_at: $json.requested_at,

      telegram: {
        chat_id: $json.chat_id,
        message_id: $json.message_id
      },

      checks: {
        health: runHealth,
        speed: runSpeed
      },

      project: {
        slug: CONFIG.project_slug,
        name: CONFIG.project_name,
        base_url: CONFIG.base_url
      },

      runners: {
        health_url: CONFIG.health_runner_url,
        health_api_key: CONFIG.health_runner_api_key,
        speed_json_url: CONFIG.speed_json_url,
        speed_image_url: CONFIG.speed_image_url,
        speed_api_key: CONFIG.speed_runner_api_key
      },

      pages: {
        home: {
          id: 'home',
          title: 'Home',
          url: homeUrl
        },
        product: {
          id: 'product',
          title: 'Product page',
          url: productUrl
        },
        cart: {
          id: 'cart',
          title: 'Cart',
          url: cartUrl,
          requires_added_product: true
        },
        references: CONFIG.speed_reference_pages
      },

      health: {
        timeout_ms: CONFIG.health_timeout_ms,
        checks: CONFIG.health_checks,
        block_resource_types: CONFIG.health_block_resource_types,
        include_screenshots: CONFIG.health_include_screenshots,
        artifact_limit: CONFIG.health_artifact_limit,
        locale: CONFIG.health_locale,
        selectors: CONFIG.selectors,
        flow: {
          clear_cart_before_test: true,
          product_url: productUrl,
          cart_url: cartUrl
        },
        product: CONFIG.product,
        expectations: CONFIG.expectations
      },

      speed: {
        device: 'desktop',
        timeout_ms: CONFIG.speed_timeout_ms,
        profile: 'datacenter',
        reference_pages: CONFIG.speed_reference_pages
      }
    }
  }
];

const data = $json;

const healthChecks = Array.isArray(data.health?.checks) ? data.health.checks : [];

const payload = {
  report_id: data.report_id,
  project: data.project,
  pages: {
    home: data.pages.home,
    product: data.pages.product,
    cart: data.pages.cart
  },
  options: {
    timeout_ms: data.health?.timeout_ms || 45000,
    checks: healthChecks,
    clear_cart_before_test: data.health?.flow?.clear_cart_before_test === true,
    block_resource_types: Array.isArray(data.health?.block_resource_types) ? data.health.block_resource_types : ['image', 'media', 'font'],
    include_screenshots: data.health?.include_screenshots === true,
    artifact_limit: data.health?.artifact_limit || 20,
    locale: data.health?.locale || 'en-US'
  },
  selectors: data.health?.selectors || {},
  product: data.health?.product || {},
  expectations: data.health?.expectations || {},
  checks: {
    ids: healthChecks
  }
};

return [{ json: { ...data, health_runner_payload: payload } }];

const original = $('Build Health Runner Payload').first().json;
let response = $json;

if (response && response.body !== undefined) response = response.body;
if (response && response.data !== undefined) response = response.data;

if (typeof response === 'string') {
  try {
    response = JSON.parse(response);
  } catch (error) {
    response = { status: 'error', skipped: false, summary: { total: 0, passed: 0, warnings: 0, failed: 1 }, checks: [], errors: ['Health runner returned invalid JSON'], warnings: [] };
  }
}

if (!response || typeof response !== 'object' || Array.isArray(response)) {
  response = { status: 'error', skipped: false, summary: { total: 0, passed: 0, warnings: 0, failed: 1 }, checks: [], errors: ['Health runner returned empty or invalid response'], warnings: [] };
}

const healthResult = {
  status: response.status || 'error',
  skipped: response.skipped === true,
  summary: response.summary || { total: 0, passed: 0, warnings: 0, failed: 1 },
  checks: Array.isArray(response.checks) ? response.checks : [],
  errors: Array.isArray(response.errors) ? response.errors : [],
  warnings: Array.isArray(response.warnings) ? response.warnings : [],
  artifacts: response.artifacts || {}
};

return [{ json: { ...original, health_runner_response: response, health_result: healthResult } }];

const data = $json;

const payload = {
  report_id: data.report_id,
  project: data.project,
  pages: {
    home: data.pages.home,
    references: data.pages.references || []
  },
  speed: {
    device: data.speed?.device || 'desktop',
    timeout_ms: data.speed?.timeout_ms || 60000,
    profile: data.speed?.profile || 'datacenter',
    reference_pages: data.speed?.reference_pages || []
  },
  timeout_ms: data.speed?.timeout_ms || 60000
};

return [{ json: { ...data, speed_runner_payload: payload } }];

const original = $('Build Speed Runner Payload').first().json;
let response = $json;

if (response && response.body !== undefined) response = response.body;
if (response && response.data !== undefined) response = response.data;

if (typeof response === 'string') {
  try {
    response = JSON.parse(response);
  } catch (error) {
    response = { ok: false, status: 'error', status_title: '❌ error', telegramMessage: '❌ <b>Speed: error</b>\n\nRunner returned invalid JSON.', primary: {}, references: {}, results: [], errors: ['Runner returned invalid JSON'] };
  }
}

if (!response || typeof response !== 'object' || Array.isArray(response)) {
  response = { ok: false, status: 'error', status_title: '❌ error', telegramMessage: '❌ <b>Speed: error</b>\n\nRunner returned empty or invalid response.', primary: {}, references: {}, results: [], errors: ['Runner returned empty or invalid response'] };
}

const speedResult = {
  ok: response.ok === true,
  skipped: response.skipped === true,
  status: response.status || 'error',
  status_title: response.status_title || '⚠️ unknown status',
  telegramMessage: response.telegramMessage || '',
  primary: response.primary && typeof response.primary === 'object' ? response.primary : {},
  references: response.references && typeof response.references === 'object' ? response.references : {},
  results: Array.isArray(response.results) ? response.results : [],
  errors: Array.isArray(response.errors) ? response.errors : []
};

return [{ json: { ...original, speed_runner_response: response, speed_result: speedResult } }];

const data = $json;

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function statusIcon(status) {
  if (status === 'ok') return '✅';
  if (status === 'warn' || status === 'warning') return '⚠️';
  if (status === 'bad' || status === 'failed' || status === 'error') return '❌';
  if (status === 'skipped') return '⏭️';
  return '•';
}

const health = data.health_result || { status: 'skipped', skipped: true, summary: { total: 0, passed: 0, warnings: 0, failed: 0 }, errors: [] };
const speed = data.speed_result || { status: 'skipped', skipped: true, telegramMessage: '', errors: [] };

const date = new Date().toLocaleString('en-GB', { timeZone: 'UTC', day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' });

const lines = [];
lines.push('📊 <b>Daily report</b>');
if (data.project?.name) lines.push(`Project: ${escapeHtml(data.project.name)}`);
lines.push(`Date: ${date} UTC`);
lines.push(`Mode: ${escapeHtml(data.run_mode)}`);
lines.push('');

if (health.skipped) {
  lines.push('⏭️ Health check skipped');
} else {
  const summary = health.summary || {};
  lines.push(`Health check: ${statusIcon(health.status)} ${summary.passed || 0}/${summary.total || 0} passed`);
  if (health.errors && health.errors.length) {
    lines.push('');
    lines.push('<b>Health errors:</b>');
    for (const err of health.errors) lines.push(`❌ ${escapeHtml(typeof err === 'string' ? err : JSON.stringify(err))}`);
  }
}

if (speed.skipped) {
  lines.push('');
  lines.push('⏭️ Speed check skipped');
} else {
  lines.push('');
  lines.push(speed.telegramMessage || `⚡ <b>Speed:</b> ${statusIcon(speed.status)} no detailed data`);
  if (speed.errors && speed.errors.length) {
    lines.push('');
    lines.push('<b>Speed errors:</b>');
    for (const err of speed.errors) lines.push(`❌ ${escapeHtml(typeof err === 'string' ? err : JSON.stringify(err))}`);
  }
}

let finalStatus = 'ok';
if ((health.summary && health.summary.failed > 0) || ['bad', 'failed', 'error'].includes(speed.status)) finalStatus = 'failed';
else if ((health.summary && health.summary.warnings > 0) || ['warn', 'warning'].includes(speed.status)) finalStatus = 'warning';

lines.push('');
lines.push(`<b>Result:</b> ${statusIcon(finalStatus)} ${finalStatus === 'ok' ? 'no critical issues' : finalStatus === 'warning' ? 'warnings found' : 'errors found'}`);

return [{ json: { ...data, final_status: finalStatus, telegram_message: lines.join('\n') } }];
